use postgres::{Client, NoTls, Error};

struct User {
    id: i32,
    name: String,
    email: String,
}

fn search_users_by_email(client: &mut Client, email: &str) -> Result<Vec<User>, Error> {
    let query = format!("SELECT id, name, email FROM users WHERE email LIKE $1");
    let rows = client.query(&query, &[&format!("%{}%", email)])?;

    let mut users = Vec::new();
    for row in rows {
        let user = User {
            id: row.get("id"),
            name: row.get("name"),
            email: row.get("email"),
        };
        users.push(user);
    }

    Ok(users)
}